   425→
   426→    socket.on("session_ended", handleSessionEnded);
   427→    return () => {
   428→      socket.off("session_ended", handleSessionEnded);
   429→    };
   430→    // eslint-disable-next-line react-hooks/exhaustive-deps
   431→  }, []);
   432→
   433→  // ── Force end from admin ──
   434→  useEffect(() => {
   435→    const handleForceEnd = (data: { user_id?: string }) => {
   436→      if (userId && data.user_id === userId) {
   437→        socket.emit("end_session", { user_id: userId });
   438→      }
