   865→/* ---------- Waiting Countdown ---------- */
   866→
   867→function WaitingCountdown() {
   868→  const [remaining, setRemaining] = useState(120);
   869→
   870→  useEffect(() => {
   871→    const timer = setInterval(() => {
   872→      setRemaining((s) => {
   873→        if (s <= 0) return 0;
   874→        return s - 1;
   875→      });
   876→    }, 1000);
   877→    return () => clearInterval(timer);
   878→  }, []);
   879→
   880→  const minutes = Math.floor(remaining / 60);
   881→  const seconds = remaining % 60;
   882→
   883→  return (
   884→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
   885→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
   886→    </p>
   887→  );
   888→}
