   706→        if (s <= 0) return 0;
   707→        return s - 1;
   708→      });
   709→    }, 1000);
   710→    return () => clearInterval(timer);
   711→  }, []);
   712→
   713→  const minutes = Math.floor(remaining / 60);
   714→  const seconds = remaining % 60;
   715→
   716→  return (
   717→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
   718→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
   719→    </p>
   720→  );
   721→}
