     1→import { useEffect, useRef, useState } from "react";
     2→
     3→interface UseCameraOptions {
     4→  width?: number;
     5→  height?: number;
     6→}
     7→
     8→interface UseCameraResult {
     9→  videoRef: React.RefObject<HTMLVideoElement | null>;
    10→  isReady: boolean;
    11→  error: string | null;
    12→}
    13→
    14→export function useCamera(options?: UseCameraOptions): UseCameraResult {
    15→  const videoRef = useRef<HTMLVideoElement | null>(null);
    16→  const [isReady, setIsReady] = useState(false);
    17→  const [error, setError] = useState<string | null>(null);
    18→  const streamRef = useRef<MediaStream | null>(null);
    19→
    20→  const requestWidth = options?.width ?? 1280;
    21→  const requestHeight = options?.height ?? 720;
    22→
    23→  useEffect(() => {
    24→    let cancelled = false;
    25→
    26→    async function startCamera() {
    27→      try {
    28→        const stream = await navigator.mediaDevices.getUserMedia({
    29→          video: { facingMode: "user", width: requestWidth, height: requestHeight },
    30→          audio: false,
    31→        });
    32→
    33→        if (cancelled) {
    34→          stream.getTracks().forEach((t) => t.stop());
    35→          return;
    36→        }
    37→
    38→        streamRef.current = stream;
    39→
    40→        if (videoRef.current) {
    41→          videoRef.current.srcObject = stream;
    42→          await videoRef.current.play();
    43→          setIsReady(true);
    44→        }
    45→      } catch (err) {
    46→        if (!cancelled) {
    47→          setError(err instanceof Error ? err.message : "Camera access denied");
    48→        }
    49→      }
    50→    }
    51→
    52→    startCamera();
    53→
    54→    return () => {
    55→      cancelled = true;
    56→      streamRef.current?.getTracks().forEach((t) => t.stop());
    57→      streamRef.current = null;
    58→      setIsReady(false);
    59→    };
    60→  }, [requestWidth, requestHeight]);
    61→
    62→  return { videoRef, isReady, error };
    63→}
    64→

