   365→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   366→          title: it.title,
   367→          price: it.price,
   368→        }));
   369→        if (clothingItems.length > 0) {
   370→          // Fade in: set opacity to 0, then transition to 1
   371→          setOutfitOpacity(0);
   372→          setCanvasOutfits((prev) => {
   373→            const next = [
   374→              ...prev,
   375→              {
   376→                name: data.outfit_name || `Outfit ${prev.length + 1}`,
   377→                items: clothingItems,
   378→                productInfo: priceInfo,
   379→              },
   380→            ];
   381→            setCanvasOutfitIndex(next.length - 1);
   382→            return next;
   383→          });
   384→          // Ramp opacity to 1 after a frame
   385→          requestAnimationFrame(() => {
   386→            requestAnimationFrame(() => {
   387→              setOutfitOpacity(1);
   388→            });
   389→          });
   390→        }
   391→        return;
   392→      }
   393→    };
   394→
   395→    socket.on("tool_result", handleToolResult);
   396→    return () => {
   397→      socket.off("tool_result", handleToolResult);
   398→    };
   399→  }, []);
   400→
   401→  // ── Session ended — show recap ──
   402→  useEffect(() => {
   403→    const handleSessionEnded = (data?: {
   404→      summary?: string;
   405→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   406→      stats?: { items_shown: number; likes: number; dislikes: number };
   407→      user_name?: string;
   408→    }) => {
   409→      stt.stopListening();
   410→      setSessionActive(false);
   411→      setCanvasOutfits([]);
   412→      setCanvasOutfitIndex(0);
   413→      setSpeechText("");
   414→      setSpeechVisible(false);
   415→
   416→      if (data && (data.summary || data.liked_items?.length || data.stats)) {
   417→        setRecapData(data);
