   438→      }
   439→    };
   440→
   441→    socket.on("session_force_end", handleForceEnd);
   442→    return () => {
   443→      socket.off("session_force_end", handleForceEnd);
   444→    };
   445→  }, [userId]);
   446→
   447→  // ── Flush queued transcripts when mira stops speaking ──
   448→  useEffect(() => {
   449→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
