   451→        user_id: userId,
   452→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   453→      });
   454→      pendingTranscriptRef.current = null;
   455→    }
   456→  }, [mira.isSpeaking, userId]);
   457→
   458→  // ── Forward final STT transcripts ──
   459→  useEffect(() => {
   460→    if (!stt.transcript || !userId) return;
   461→
   462→    if (mira.isSpeaking) {
   463→      pendingTranscriptRef.current = stt.transcript;
   464→    } else {
   465→      socket.emit("mirror_event", {
   466→        user_id: userId,
   467→        event: { type: "voice", transcript: stt.transcript },
   468→      });
   469→    }
   470→    // eslint-disable-next-line react-hooks/exhaustive-deps
   471→  }, [stt.transcript, userId]);
   472→
   473→  // ── Snapshot handler ──
   474→  useEffect(() => {
   475→    const handleSnapshotRequest = () => {
   476→      const video = videoRef.current;
   477→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   478→
   479→      const canvas = document.createElement("canvas");
   480→      canvas.width = video.videoWidth;
   481→      canvas.height = video.videoHeight;
   482→      const ctx = canvas.getContext("2d");
   483→      if (!ctx) return;
   484→
   485→      ctx.drawImage(video, 0, 0);
   486→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   487→      const base64 = dataUrl.split(",")[1];
   488→
   489→      socket.emit("mirror_event", {
   490→        type: "snapshot",
   491→        image_base64: base64,
   492→        user_id: userId,
   493→      });
   494→    };
   495→
   496→    socket.on("request_snapshot", handleSnapshotRequest);
   497→    return () => {
   498→      socket.off("request_snapshot", handleSnapshotRequest);
   499→    };
   500→  }, [videoRef, userId]);
   501→
   502→  // ── Gesture handler ──
   503→  const handleGesture = useCallback(
   504→    (gesture: DetectedGesture) => {
   505→      setLastGesture(gesture.type);
   506→      gestureKeyRef.current += 1;
   507→      setGestureKey(gestureKeyRef.current);
   508→
   509→      if (canvasOutfits.length > 1) {
   510→        if (gesture.type === "swipe_left") {
   511→          setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   512→        } else if (gesture.type === "swipe_right") {
   513→          setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   514→        }
   515→      }
   516→
   517→      socket.emit("mirror_event", {
   518→        user_id: userId,
   519→        event: {
   520→          type: "gesture",
   521→          gesture: gesture.type,
   522→          confidence: gesture.confidence,
   523→          timestamp: gesture.timestamp,
   524→        },
   525→      });
   526→    },
   527→    [userId, canvasOutfits.length],
   528→  );
   529→
   530→  useGestureRecognizer({
   531→    videoRef,
   532→    isVideoReady: isCameraReady,
   533→    onGesture: handleGesture,
   534→  });
   535→
   536→  // ── Keyboard shortcuts ──
   537→  useEffect(() => {
   538→    function handleKeyDown(e: KeyboardEvent) {
   539→      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
   540→        return;
   541→      }
   542→
   543→      switch (e.key) {
